// Off-chain: generate proof
import { groth16 } from 'snarkjs';
const { proof, publicSignals } = await groth16.fullProve(
  inputs, 'circuit.wasm', 'circuit_final.zkey'
);

// Format for the Solidity verifier
const a: [bigint, bigint] = [BigInt(proof.pi_a[0]), BigInt(proof.pi_a[1])];
const b: [[bigint,bigint],[bigint,bigint]] = [
  [BigInt(proof.pi_b[0][1]), BigInt(proof.pi_b[0][0])],
  [BigInt(proof.pi_b[1][1]), BigInt(proof.pi_b[1][0])]
];
const c: [bigint, bigint] = [BigInt(proof.pi_c[0]), BigInt(proof.pi_c[1])];
const inputs = publicSignals.map(BigInt);

// On-chain: verify
const valid = await client.readContract({
  address: VERIFIER, abi: VERIFIER_ABI, functionName: 'verifyProof',
  args: [a, b, c, inputs]
});
if (!valid) throw new Error('Invalid proof');
